INSERT INTO `eng-dhcp-sections` VALUES (5,'Header','####### Global options ############\r\n\r\nauthoritative;\r\n\r\n\r\noption subnet-mask		 	255.255.255.0;\r\noption domain-name-servers	130.209.176.24, 130.209.12.207, 130.209.176.9, 130.209.176.2, 130.209.16.6;\r\n#option domain-name-servers     130.209.12.207, 130.209.176.9, 130.209.176.2, 130.209.16.6;\r\n#option netbios-name-servers 130.209.176.9, 130.209.12.193;\r\n \r\noption wpad code 252 = text;\r\noption wpad \"\\n\\000\";\r\n\r\ndeny unknown-clients;	\r\nddns-update-style	none;\r\n\r\n#server-name \"pixie.eng-ad.gla.ac.uk\";\r\n#server-name \"leprechaun.eng-ad.gla.ac.uk\";\r\n#filename \"\\\\boot\\\\x64\\\\pxelinux.com\";\r\n#next-server 130.209.176.18;\r\n\r\noption arch code 93 = unsigned integer 16;\r\nif option arch = 00:07 or option arch = 00:09 {\r\n      server-name \"pixie.eng-ad.gla.ac.uk\";\r\n#      server-name \"leprechaun.eng.gla.ac.uk\";\r\n      filename \"ipxe.efi\";\r\n#      next-server 172.20.176.16;\r\n      next-server 130.209.176.18;\r\n} else {\r\n      server-name \"pixie.eng-ad.gla.ac.uk\";\r\n#      filename \"\\\\boot\\\\x64\\\\pxelinux.com\";\r\n#      next-server 130.209.176.18;\r\n#      server-name \"leprechaun.eng.gla.ac.uk\";\r\n      filename \"undionly.kpxe\";\r\n#      next-server 172.20.176.16;\r\n      next-server 130.209.176.18;\r\n}\r\n\r\nmax-lease-time 900;\r\ndefault-lease-time 900;\r\n\r\n# set specific syslog type so can be filtered more easily on the loghost (davdi.eng)\r\nlog-facility local0;\r\n\r\n#####################################################'),(6,'Subnets','########### subnets\r\n\r\nshared-network sub176 {\r\n	subnet 130.209.176.0 netmask 255.255.255.0 {\r\n		option routers		      	130.209.176.1;\r\n                range                           130.209.176.27 130.209.176.28;\r\n                range 				130.209.176.45 130.209.176.47;   #added jt november 19 2014\r\n		range				130.209.176.50 130.209.176.53; #added 50,51 jt 30/01/15\r\n           